import React from 'react';
import { motion } from 'framer-motion';
import { GraduationCap, Award, BookOpen } from 'lucide-react';

const About = () => {
  const education = [
    {
      title: "B.Tech Computer Science & Engineering",
      institution: "CT University",
      period: "Present",
      icon: <GraduationCap size={24} className="text-primary" />,
      description: "Pursuing bachelor's degree with a focus on core computer science subjects, software engineering, and modern technologies."
    },
    {
      title: "Higher Secondary (12th Standard)",
      institution: "State Board",
      period: "Completed",
      score: "92.4%",
      icon: <Award size={24} className="text-accent" />,
      description: "Excelled in science and mathematics, building a strong analytical foundation."
    },
    {
      title: "Secondary (10th Standard)",
      institution: "State Board",
      period: "Completed",
      score: "98.0%",
      icon: <BookOpen size={24} className="text-secondary" />,
      description: "Outstanding academic performance reflecting dedication and consistent effort."
    }
  ];

  return (
    <section className="py-24 relative" id="about">
      <div className="container mx-auto px-6">
        <div className="flex flex-col mb-16">
          <motion.h2 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="text-4xl font-bold text-white mb-4"
          >
            About & Education
          </motion.h2>
          <motion.div 
            initial={{ opacity: 0, width: 0 }}
            whileInView={{ opacity: 1, width: "60px" }}
            viewport={{ once: true }}
            className="h-1 bg-gradient-to-r from-primary to-accent rounded-full"
          ></motion.div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
          {/* Bio Side */}
          <motion.div 
            initial={{ opacity: 0, x: -20 }}
            whileInView={{ opacity: 1, x: 0 }}
            viewport={{ once: true }}
            className="bg-surface/50 border border-white/5 p-8 rounded-3xl"
          >
            <h3 className="text-2xl font-semibold text-white mb-6">Who am I?</h3>
            <p className="text-gray-400 leading-relaxed mb-6">
              I am currently pursuing my B.Tech in Computer Science and Engineering at CT University. I have a profound interest in problem-solving, which has driven me to solve over <strong className="text-primary font-bold">750 questions on LeetCode</strong>, honing my Data Structures and Algorithms skills.
            </p>
            <p className="text-gray-400 leading-relaxed">
              Beyond competitive programming, I am a passionate developer. I specialize in the MERN stack for robust web development, and I am deeply involved in exploring Machine Learning and Generative AI to build smart, data-driven applications.
            </p>
          </motion.div>

          {/* Education Timeline */}
          <div className="space-y-6">
            {education.map((item, index) => (
              <motion.div 
                key={index}
                initial={{ opacity: 0, x: 20 }}
                whileInView={{ opacity: 1, x: 0 }}
                viewport={{ once: true }}
                transition={{ delay: index * 0.1 }}
                className="flex gap-6 bg-surface/30 p-6 rounded-2xl border border-white/5 hover:border-white/10 transition-colors"
              >
                <div className="flex-shrink-0 w-12 h-12 rounded-full bg-white/5 flex items-center justify-center">
                  {item.icon}
                </div>
                <div>
                  <h4 className="text-lg font-semibold text-gray-100">{item.title}</h4>
                  <div className="flex items-center gap-3 mt-1 mb-2 text-sm">
                    <span className="text-primary font-medium">{item.institution}</span>
                    <span className="text-gray-600">•</span>
                    <span className="text-gray-400 pl-1">{item.period}</span>
                  </div>
                  {item.score && (
                    <div className="inline-block px-3 py-1 rounded-md bg-white/5 text-accent text-xs font-bold mb-3 border border-accent/20">
                      Score: {item.score}
                    </div>
                  )}
                  <p className="text-gray-500 text-sm leading-relaxed">{item.description}</p>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;

import React from 'react';
import { motion } from 'framer-motion';
import { ChevronRight } from 'lucide-react';

const Hero = () => {
  return (
    <section className="relative min-h-[100dvh] flex items-center pt-24 pb-12 overflow-hidden" id="hero">
      {/* Background glow elements */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[400px] h-[400px] md:w-[600px] md:h-[600px] bg-primary/20 rounded-full blur-[100px] md:blur-[120px] opacity-40 md:opacity-50 z-0 pointer-events-none mix-blend-screen"></div>

      <div className="container mx-auto px-6 relative z-10 flex flex-col items-center md:items-start text-center md:text-left mt-10 md:mt-0">
        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="inline-flex items-center space-x-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 mb-8"
        >
          <span className="w-2 h-2 rounded-full bg-green-500 animate-[pulse_2s_ease-in-out_infinite]"></span>
          <span className="text-sm font-medium text-gray-300">Available for new opportunities</span>
        </motion.div>

        <motion.h1 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.1 }}
          className="text-5xl md:text-7xl lg:text-8xl font-extrabold tracking-tight text-white mb-6 leading-tight flex flex-col md:block"
        >
          Hi, I'm <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-accent">Pourush</span>
        </motion.h1>

        <motion.p 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.2 }}
          className="text-lg md:text-xl text-gray-400 max-w-2xl mb-10 leading-relaxed font-light"
        >
          A passionate <strong className="text-gray-200 font-medium">B.Tech CSE Student</strong> & <strong className="text-gray-200 font-medium">Full-Stack Developer</strong> crafting scalable web apps and exploring the frontiers of Machine Learning & Generative AI.
        </motion.p>

        <motion.div 
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.3 }}
          className="flex flex-col sm:flex-row items-center gap-4 w-full sm:w-auto"
        >
          <a href="#projects" className="w-full sm:w-auto justify-center px-8 py-4 bg-primary text-white font-semibold rounded-xl hover:bg-primary/90 transition-all flex items-center gap-2 group shadow-[0_0_20px_rgba(139,92,246,0.3)]">
            Explore My Work
            <ChevronRight size={20} className="group-hover:translate-x-1 transition-transform" />
          </a>
          <a href="#contact" className="w-full sm:w-auto justify-center px-8 py-4 bg-white/5 text-white font-semibold rounded-xl hover:bg-white/10 border border-white/10 transition-all text-center">
            Contact Me
          </a>
        </motion.div>
      </div>
    </section>
  );
};

export default Hero;

import React, { useState, useEffect } from 'react';
import { Menu, X, Code2 } from 'lucide-react';
import { motion } from 'framer-motion';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'About', href: '#about' },
    { name: 'Skills', href: '#skills' },
    { name: 'Projects', href: '#projects' },
    { name: 'Contact', href: '#contact' },
  ];

  return (
    <header className={`fixed top-0 w-full z-50 transition-all duration-300 border-b border-white/5 ${scrolled ? 'bg-surface/90 backdrop-blur-md py-4 shadow-lg' : 'bg-transparent py-6'}`}>
      <div className="container mx-auto px-6 flex items-center justify-between">
        <a href="#" className="flex items-center space-x-2 text-primary">
          <Code2 size={28} />
          <span className="font-bold text-xl tracking-tight text-gray-100">Pourush<span className="text-primary">.dev</span></span>
        </a>

        {/* Desktop Nav */}
        <nav className="hidden md:flex items-center space-x-8">
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} className="text-sm font-medium text-gray-300 hover:text-primary transition-colors cursor-pointer">
              {link.name}
            </a>
          ))}
          <a href="https://github.com/Pourushkashyap" target="_blank" rel="noreferrer" className="px-5 py-2 text-sm font-medium bg-primary text-white rounded-full hover:bg-primary/90 transition-all transform hover:scale-105 shadow-[0_0_15px_rgba(139,92,246,0.3)]">
            GitHub
          </a>
        </nav>

        {/* Mobile Toggle */}
        <button className="md:hidden text-gray-300 hover:text-white" onClick={() => setIsOpen(!isOpen)}>
          {isOpen ? <X size={26} /> : <Menu size={26} />}
        </button>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <motion.div 
          initial={{ opacity: 0, height: 0 }}
          animate={{ opacity: 1, height: 'auto' }}
          className="absolute top-full left-0 w-full bg-surface border-b border-white/10 py-4 px-6 flex flex-col space-y-4 shadow-2xl md:hidden overflow-hidden"
        >
          {navLinks.map((link) => (
            <a key={link.name} href={link.href} onClick={() => setIsOpen(false)} className="text-gray-300 hover:text-primary transition-colors font-medium block w-full">
              {link.name}
            </a>
          ))}
          <a href="https://github.com/Pourushkashyap" target="_blank" rel="noreferrer" className="text-primary font-medium mt-2">
            View GitHub Profile &rarr;
          </a>
        </motion.div>
      )}
    </header>
  );
};

export default Navbar;

import React from 'react';
import { motion } from 'framer-motion';
import { Github, Activity, MessageSquare, Briefcase, Dumbbell } from 'lucide-react';

const Projects = () => {
  const projects = [
    {
      title: "Fingrow",
      description: "A secure and scalable peer-to-peer connection system designed specifically to facilitate user loans. Users can connect, negotiate, and manage loans effectively.",
      tech: ["React.js", "Node.js", "MongoDB", "Express", "Tailwind CSS"],
      icon: <Activity className="text-primary" size={28} />,
      github: "https://github.com/Pourushkashyap",
      gradient: "from-blue-500/10 to-purple-500/10"
    },
    {
      title: "Real-Time Chat Application",
      description: "A fast, responsive, and real-time messaging platform enabling users to communicate instantly through web sockets.",
      tech: ["MERN Stack", "Socket.io", "React Context API", "JWT"],
      icon: <MessageSquare className="text-accent" size={28} />,
      github: "https://github.com/Pourushkashyap",
      gradient: "from-cyan-500/10 to-blue-500/10"
    },
    {
      title: "ATS Score Checker",
      description: "An intelligent Machine Learning model that evaluates resumes against job descriptions, calculating an ATS compatibility score to help job seekers.",
      tech: ["Python", "Machine Learning", "NLP"],
      icon: <Briefcase className="text-emerald-400" size={28} />,
      github: "https://github.com/Pourushkashyap",
      gradient: "from-emerald-500/10 to-teal-500/10"
    },
    {
      title: "AI Gym Recommendation System",
      description: "A Machine Learning driven application that curates personalized gym routines and plans based on user metrics and fitness goals.",
      tech: ["Python", "Scikit-Learn", "Pandas"],
      icon: <Dumbbell className="text-orange-400" size={28} />,
      github: "https://github.com/Pourushkashyap",
      gradient: "from-orange-500/10 to-red-500/10"
    }
  ];

  return (
    <section className="py-24 relative" id="projects">
      <div className="container mx-auto px-6">
        <div className="flex flex-col mb-16 items-center text-center">
          <motion.h2 
            initial={{ opacity: 0, y: 20 }}
            whileInView={{ opacity: 1, y: 0 }}
            viewport={{ once: true }}
            className="text-4xl font-bold text-white mb-4"
          >
            Featured Projects
          </motion.h2>
          <motion.div 
            initial={{ opacity: 0, width: 0 }}
            whileInView={{ opacity: 1, width: "60px" }}
            viewport={{ once: true }}
            className="h-1 bg-gradient-to-r from-primary to-accent rounded-full"
          ></motion.div>
          <p className="mt-6 text-gray-400 max-w-2xl leading-relaxed">
            A selection of my recent works ranging from full-stack web applications to machine learning models, demonstrating my diverse technical capabilities.
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          {projects.map((project, index) => (
            <motion.div
              key={index}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
              className={`p-8 rounded-3xl border border-white/10 bg-gradient-to-br ${project.gradient} bg-surface/30 backdrop-blur-sm relative overflow-hidden group hover:border-primary/50 transition-colors duration-500 flex flex-col h-full`}
            >
              <div className="absolute top-0 right-0 w-40 h-40 bg-white/5 rounded-bl-full -z-10 group-hover:scale-110 group-hover:bg-primary/10 transition-all duration-500"></div>

              <div className="flex justify-between items-start mb-6">
                <div className="p-4 bg-surface/80 rounded-2xl border border-white/5 shadow-xl group-hover:-translate-y-1 transition-transform">
                  {project.icon}
                </div>
                <div className="flex gap-3">
                  <a href={project.github} target="_blank" rel="noreferrer" className="text-gray-400 hover:text-white transition-colors bg-surface/80 p-2.5 rounded-full hover:bg-primary border border-white/5 shadow-lg group-hover:-translate-y-1">
                    <Github size={20} />
                  </a>
                </div>
              </div>

              <h3 className="text-2xl font-bold text-white mb-4">{project.title}</h3>
              <p className="text-gray-300 mb-8 leading-relaxed text-sm flex-grow">
                {project.description}
              </p>

              <div className="flex flex-wrap gap-2 mt-auto">
                {project.tech.map((tech, i) => (
                  <span key={i} className="px-3 py-1 bg-surface/80 text-primary text-xs font-semibold rounded-full border border-primary/20 hover:bg-primary/20 transition-colors">
                    {tech}
                  </span>
                ))}
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Projects;

import React from 'react';
import { motion } from 'framer-motion';
import { Database, BrainCircuit, Globe, Server, Terminal, Laptop } from 'lucide-react';

const Skills = () => {
  const skillCategories = [
    {
      title: "Problem Solving",
      icon: <Terminal className="text-primary" size={32} />,
      items: ["Data Structures", "Algorithms", "Optimization"],
      highlight: "750+ LeetCode Questions Solved"
